SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum((bs."out.electricity.total.energy_consumption" - bs."out.natural_gas.total.energy_consumption") * bs.weight) AS elec_minus_gas FROM resstock_2024_amy2018_release_2_metadata AS bs WHERE bs.applicability = true AND bs.upgrade = 0 AND bs."in.state" IN ('CO', 'WY') GROUP BY 1 ORDER BY 1